#!/usr/bin/env python3\nimport bittensor as bt\nimport json\nfrom datetime import datetime\n\nsub = bt.Subtensor(network='finney')\ncoldkey = '5Cexeg7deNSTzsqMKuBmvc9JHGHymuL4SdjAA9Jw4eeHUphb'\n\nprint('=== Bittensor Chain Data ===')\nprint('Subnets:', sub.get_subnet_count())\nprint('Network stake:', sub.get_current_network_stake())\nprint('TAO supply:', sub.get_current_supply())\nprint('\\n=== Subnet Stakes (top 20) ===')\nstakes = []\nfor netuid in range(min(50, sub.get_subnet_count())):\n    stake = sub.get_subnet_stake(netuid)\n    stakes.append({'netuid': netuid, 'stake': float(stake)})\nstakes.sort(key=lambda x: x['stake'], reverse=True)\nfor s in stakes[:20]:\n    print(f'SN{s[\"netuid\"]}: {s[\"stake\"]:,.0f} TAO')\nprint('\\n=== My Delegations? ===')\n# Test possible queries\ntry:\n    # No direct nominator list; validators only\n    pass\nexcept Exception as e:\n    print('Delegations query:', e)\nprint('\\n=== Incentive/Emissions Proxy ===')\n# Incentive per subnet recent\nfor netuid in [0,3,4,9,62,64,120]:\n    try:\n        mg = bt.metagraph(netuid=netuid)\n        print(f'SN{netuid} incentive avg:', mg.incentive.mean())\n    except:\n        print(f'SN{netuid} metagraph fail')\n\n# Snapshot\nsnapshot = {\n    'date': datetime.now().isoformat(),\n    'subnets': {s['netuid']: s['stake'] for s in stakes[:20]},\n    'network_stake': float(sub.get_current_network_stake())\n}\nprint('\\nSample snapshot:', json.dumps(snapshot, indent=2))\n\nwith open('bt_snapshot.json', 'w') as f:\n    json.dump(snapshot, f, indent=2)\nprint('Snapshot saved: bt_snapshot.json')